/// A domain that is used to redirect email recipients to an Amazon SES-operated
/// domain. This
/// domain captures open and click events generated by Amazon SES emails.
///
/// For more information, see [Configuring Custom
/// Domains to Handle Open and Click
/// Tracking](https://docs.aws.amazon.com/ses/latest/dg/configure-custom-open-click-domains.html) in the *Amazon SES Developer
/// Guide*.
pub const TrackingOptions = struct {
    /// The custom subdomain that is used to redirect email recipients to the Amazon
    /// SES event
    /// tracking domain.
    custom_redirect_domain: ?[]const u8 = null,
};
